    "text_content": "Caso o valor seja superado, a detentora de conta deve negar a transação solicitada pela iniciadora.\" }, \"transactionLimit\": { \"type\": \"string\", \"pattern\": \"^((\\\\d{1,16}\\\\.\\\\d{2}))$\", \"minLength\": 4, \"maxLength\": 19, \"example\": \"1000000.12\", \"description\": \"Valor máximo para cada transação de pagamento associada a esse consentimento. Caso valor do pagamento seja maior que esse limite, a detentora de contas deve rejeitar a transação de pagamento.\" }, \"periodicLimits\": { \"type\": \"object\", \"description\": \"Limites transacionais por período determinado pelo usuário pagador.\", \"properties\": { \"day\": { \"type\": \"object\", \"description\": \"Configurar limite transacional diário determinado pelo usuário pagador.\\n\\n[Restrição] Caso enviado o objeto, ao menos um dos campos (`quantityLimit` ou `transactionLimit`) devem ser preenchidos.\\n\", \"properties\": { \"quantityLimit\": { \"type\": \"integer\", \"minimum\": 1, \"example\": 2, \"description\": \"Quantidade limite de transações permitidas para ocorrer durante um dia.\" }, \"transactionLimit\": { \"type\": \"string\", \"pattern\": \"^((\\\\d{1,16}\\\\.\\\\d{2}))$\", \"minLength\": 4, \"maxLength\": 19, \"example\": \"100000.12\", \"description\": \"Valor máximo a ser transacionado diariamente.\" } } }, \"week\": { \"type\": \"object\", \"description\": \"Configurar limite transacional semanal determinado pelo usuário pagador.\\n\\n[Restrição] Caso enviado o objeto, ao menos um dos campos (`quantityLimit` ou `transactionLimit`) devem ser preenchidos\\n\", \"properties\": { \"quantityLimit\": { \"type\": \"integer\", \"minimum\": 1, \"example\": 10, \"description\": \"Quantidade limite de transações permitidas para ocorrer durante uma semana.\" }, \"transactionLimit\": { \"type\": \"string\", \"pattern\": \"^((\\\\d{1,16}\\\\.\\\\d{2}))$\", \"minLength\": 4, \"maxLength\": 19, \"example\": \"100000.12\", \"description\": \"Valor máximo a ser transacionado semanalmente.\" } } }, \"month\": { \"type\": \"object\", \"description\": \"Configurar limite transacional mensal determinado pelo usuário pagador.\\n\\n[Restrição] Caso enviado o objeto, ao menos um dos campos (`quantityLimit` ou `transactionLimit`) devem ser preenchidos\\n\", \"properties\": { \"quantityLimit\": { \"type\": \"integer\", \"minimum\": 1, \"example\": 30, \"description\": \"Quantidade limite de transações permitidas para ocorrer durante um mês.\" }, \"transactionLimit\": { \"type\": \"string\", \"pattern\": \"^((\\\\d{1,16}\\\\.\\\\d{2}))$\", \"minLength\": 4, \"maxLength\": 19, \"example\": \"100000.12\", \"description\": \"Valor máximo a ser transacionado mensalmente.\" } } }, \"year\": { \"type\": \"object\", \"description\": \"Configurar limite transacional anual determinado pelo usuário pagador.\\n\\n[Restrição] Caso enviado o objeto, ao menos um dos campos (`quantityLimit` ou `transactionLimit`) devem ser preenchidos\\n\", \"properties\": { \"quantityLimit\": { \"type\": \"integer\", \"minimum\": 1, \"example\": 100, \"description\": \"Quantidade limite de transações permitidas para ocorrer durante um ano.\" }, \"transactionLimit\": { \"type\": \"string\", \"pattern\": \"^((\\\\d{1,16}\\\\.\\\\d{2}))$\", \"minLength\": 4, \"maxLength\": 19, \"example\": \"100000.12\", \"description\": \"Valor máximo a ser transacionado por um ano, a partir da data definida no campo `/data/startDateTime`.\" } } } } }, \"startDateTime\": { \"type\": \"string\", \"format\": \"date-time\", \"pattern\": \"^(\\\\d{4})-(1[0-2]|0?[",
