    "text_content": "1-9])-(3[01]|[12][0-9]|0?[ 1-9])T(?:[01]\\\\d|2[0123]):(?:[012345]\\\\d):(?:[012345]\\\\d)Z$\", \"maxLength\": 20, \"description\": \"Data e hora em que o consentimento foi revogado\" }, \"reason\": { \"type\": \"object\", \"description\": \"Informações sobre o motivo da revogação\\n\", \"required\": [ \"code\", \"detail\" ], \"properties\": { \"code\": { \"type\": \"string\", \"enum\": [ \"NAO_INFORMADO\", \"REVOGADO_USUARIO\", \"REVOGADO_RECEBEDOR\" ], \"example\": \"REVOGADO_RECEBEDOR\", \"description\": \"Código indicador do motivo da revogação\\n\" }, \"detail\": { \"type\": \"string\", \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"maxLength\": 2048, \"description\": \"Detalhe sobre o motivo de revogação indicado no campo `/data/revocation/reason/code`.\\n- NAO_INFORMADO: Não informada pela detentora de conta;\\n- REVOGADO_USUARIO: O usuário pagador revogou a recorrência do consentimento;\\n- REVOGADO_RECEBEDOR: O usuário recebedor revogou a recorrência do consentimento.\\n\", \"example\": \"O usuário rejeitou a autorização do consentimento\" } } } } }, \"recurringConfiguration\": { \"type\": \"object\", \"description\": \"Campo destinado a configuração dos diferentes produtos de pagamentos recorrentes.\", \"oneOf\": [ { \"type\": \"object\", \"required\": [ \"automatic\" ], \"properties\": { \"automatic\": { \"type\": \"object\", \"description\": \"Definição da configuração de recorrência para pagamentos automáticos\", \"required\": [ \"contractId\", \"interval\", \"contractDebtor\", \"isRetryAccepted\", \"useOverdraftLimit\", \"referenceStartDate\" ], \"properties\": { \"contractId\": { \"type\": \"string\", \"pattern\": \"^[a-zA-Z0-9]{1,35}$\", \"minLength\": 1, \"maxLength\": 35, \"example\": \"XE00038166201907261559y6j6\", \"description\": \"Identificador do contrato do cliente localizado no ambiente do recebedor.",
